{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "title": "Requirement",
  "type": "object",
  "required": ["requirement_id", "title", "description", "acceptance_criteria", "status"],
  "properties": {
    "requirement_id": { "type": "string", "pattern": "^REQ-[A-Z0-9]{6,}$" },
    "title": { "type": "string", "minLength": 3 },
    "description": { "type": "string", "minLength": 10 },
    "acceptance_criteria": {
      "type": "array",
      "minItems": 1,
      "items": { "type": "string", "minLength": 3 }
    },
    "status": { "type": "string", "enum": ["draft", "approved", "implemented", "rejected"] }
  },
  "additionalProperties": false
}

