import secrets


def _new_id(prefix: str) -> str:
    token = secrets.token_hex(4).upper()
    return f"{prefix}-{token}"


def new_requirement_id() -> str:
    return _new_id("REQ")


def new_work_item_id() -> str:
    return _new_id("WI")


def new_evidence_id() -> str:
    return _new_id("EVD")

import jsonschema

from echocode.app import PROJECT_ROOT
from echocode.utils.json_tools import load_json_file


def _load_schema(schema_name: str) -> dict:
    schema_path = PROJECT_ROOT / "schemas" / schema_name
    return load_json_file(schema_path)


def validate_requirement_payload(payload: dict) -> None:
    jsonschema.validate(instance=payload, schema=_load_schema("requirement.schema.json"))


def validate_work_item_payload(payload: dict) -> None:
    jsonschema.validate(instance=payload, schema=_load_schema("work-item.schema.json"))


def validate_evidence_bundle_payload(payload: dict) -> None:
    jsonschema.validate(instance=payload, schema=_load_schema("evidence-bundle.schema.json"))

from dataclasses import dataclass, field

from echocode.domain.models import WorkItem


@dataclass
class TraceabilityService:
    records: list[dict[str, object]] = field(default_factory=list)

    def link_work_item(self, requirement_ids: list[str], work_item: WorkItem) -> dict[str, object]:
        record = {
            "work_item_id": work_item.work_item_id,
            "requirement_ids": requirement_ids,
            "design_ids": work_item.design_ids,
            "expected_outcomes": work_item.expected_outcomes,
            "status": work_item.status.value,
        }
        self.records.append(record)
        return record

